mapper.select:
SELECT id, request_id, user_id, api_key_id, provider_id, model_id,
       status_code, latency_ms, error_code, created_at
FROM request_log
WHERE user_id = #{userId}
ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT id, request_id, user_id, api_key_id, provider_id, model_id,
       status_code, latency_ms, error_code, created_at
FROM request_log


        AND user_id = #{userId}


        AND model_id = #{modelId}


        AND status_code = #{statusCode}


        AND created_at >= #{startTime}


        AND created_at <= #{endTime}


ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM request_log


        AND user_id = #{userId}


        AND model_id = #{modelId}


        AND status_code = #{statusCode}


        AND created_at >= #{startTime}


        AND created_at <= #{endTime}

SELECT m.id AS model_id, m.code AS model_code, m.display_name AS model_display_name, COUNT(r.id) AS request_count, SUM(CASE WHEN r.status_code >= 400 OR r.error_code IS NOT NULL THEN 1 ELSE 0 END) AS error_count, ROUND( SUM(CASE WHEN r.status_code >= 400 OR r.error_code IS NOT NULL THEN 1 ELSE 0 END) / COUNT(r.id), 4 ) AS error_rate, AVG(r.latency_ms) AS avg_latency_ms FROM request_log r INNER JOIN model m ON m.id = r.model_id
AND r.created_at >= #{startTime}
AND r.created_at <= #{endTime}
GROUP BY m.id, m.code, m.display_name ORDER BY request_count DESC, m.id ASC
